import React, { useEffect, useState } from "react";
import { useParams } from "react-router-dom";

const ProductDetails = () => {
  const { id } = useParams(); // Ensure that 'id' is correctly retrieved from the URL params
  const [product, setProduct] = useState(null);
  const [userType, setUserType] = useState(null); // State to hold user type

  useEffect(() => {
    const fetchProduct = async () => {
      try {
        // Fetch product details
        const response = await fetch(`http://localhost:5000/product/getSingleProduct/${id}`);
        if (!response.ok) {
          throw new Error("Failed to fetch product");
        }
        const jsonData = await response.json();
        setProduct(jsonData);
      } catch (err) {
        console.error(err.message);
      }
    };

    // Fetch user type
    const fetchUserType = async () => {
      try {
        const response = await fetch("http://localhost:5000/auth/getUserType", {
          method: "GET",
          headers: { "jwtToken": localStorage.getItem("jwtToken") }
        });
        if (!response.ok) {
          throw new Error("Failed to fetch user type");
        }
        const userTypeData = await response.json();
        setUserType(userTypeData.userType);
      } catch (err) {
        console.error(err.message);
      }
    };

    fetchProduct();
    fetchUserType();
  }, [id]);

  return (
    <div>
      <h2>Product Details</h2>
      {product && (
        <div>
          <p>Product Name: {product.product_name}</p>
          <p>Price: {product.price}</p>
          <p>Category: {product.product_category}</p>
          <p>Features: {product.product_features}</p>
          <p>Status: {product.status}</p>
          {userType === "customer" && (
            <div>
              <button>Add to Cart</button>
              <button>Buy Now</button>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export default ProductDetails;
